sql:
SELECT mandi_name
FROM mandis
WHERE total_traders = (SELECT MAX(total_traders) FROM mandis);

SELECT mandi_name, total_traders
FROM mandis
ORDER BY total_traders DESC;

external_knowledge:
- 'Most active' in this context refers to the highest number of traders; 
- 'Active' mandis are those where the 'active_status' is 1; 
- The 'Punjab' region is one of the regions where the mandis are located.

sql:
SELECT generated_by, COUNT(*) as total_reports
FROM market_reports
GROUP BY generated_by;

SELECT DISTINCT mandi_name 
FROM mandis 
WHERE region = 'Punjab';

external_knowledge:
- 'Vibrant marketplaces' refers to active mandis (markets) where the active_status equals 1; 
- 'Where the price is on the rise' refers to the price_trend being 'increasing'; 
- 'Business is booming' refers to active mandis.

sql:
SELECT 
  (SELECT SUM(total_traders) FROM mandis) AS total_traders_registered,
  (SELECT COUNT(DISTINCT generated_by) FROM market_reports) AS total_distinct_report_generators;
